INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (1, 'game', 'Hades II', 'hades-2', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1145350/91ac334a2c137d08968ccc0bc474a02579602100/header.jpg?t=1779901265', NULL, 'Battle beyond the Underworld using dark sorcery to take on the Titan of Time in this bewitching sequel to the award-winning rogue-like dungeon crawler.', '{\"genre\": \"Action, Indie, RPG\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/TUOERgENrVs\", \"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1Wx4y1W7Gh\"}, \"demo_url\": \"steam://install/2846690\", \"platform\": \"\", \"developer\": \"Supergiant Games\", \"demo_available\": true}', 'https://www.youtube.com/embed/TUOERgENrVs', NULL, 'https://store.steampowered.com/app/1145350/', NULL, 'manual', 1, '2026-05-27 18:06:01', '2026-06-03 16:33:28', 1);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (3, 'game', 'Black Myth: Wukong', 'black-myth-wukong', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2358720/header.jpg?t=1760601605', NULL, 'Black Myth: Wukong is an action RPG rooted in Chinese mythology. You shall set out as the Destined One to venture into the challenges and marvels ahead, to uncover the obscured truth beneath the veil of a glorious legend from the past.', '{\"genre\": \"Action, Adventure, RPG\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/u83Vd6AVyf4\", \"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1ex4y1J7JE\"}, \"demo_url\": \"steam://install/2581550\", \"platform\": \"\", \"developer\": \"Game Science\", \"demo_available\": true}', 'https://www.youtube.com/embed/u83Vd6AVyf4', NULL, 'https://store.steampowered.com/app/2358720/', NULL, 'manual', 1, '2026-05-27 18:06:01', '2026-06-03 16:33:28', 0);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (5, 'game', 'Elden Ring: Nightreign', 'elden-ring-nightreign', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1245620/header.jpg?t=1767883716', NULL, 'THE CRITICALLY ACCLAIMED FANTASY ACTION RPG. Rise, Tarnished, and be guided by grace to brandish the power of the Elden Ring and become an Elden Lord in the Lands Between.', '{\"genre\": \"Action, RPG\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/L4Lq1yOhCgY\", \"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1uT411677U\"}, \"platform\": \"\", \"developer\": \"FromSoftware, Inc.\", \"demo_available\": false}', 'https://www.youtube.com/embed/L4Lq1yOhCgY', NULL, 'https://store.steampowered.com/app/1245620/', NULL, 'manual', 1, '2026-05-27 18:06:01', '2026-05-27 20:07:55', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (6, 'game', 'Hollow Knight: Silksong', 'hollow-knight-silksong', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1030300/7983574d464e6559ac7e24275727f73a8bcca1f3/header.jpg?t=1776125736', NULL, 'Discover a vast, haunted kingdom in Hollow Knight: Silksong! Explore, fight and survive as you ascend to the peak of a land ruled by silk and song.', '{\"genre\": \"Action, Adventure, Indie\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/pFAknD_9U7c\", \"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1iW4y1x7nx\"}, \"platform\": \"\", \"developer\": \"Team Cherry\", \"demo_available\": false}', 'https://www.youtube.com/embed/pFAknD_9U7c', NULL, 'https://store.steampowered.com/app/1030300/', NULL, 'manual', 1, '2026-05-27 18:06:01', '2026-05-27 20:07:55', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (7, 'game', 'Metaphor: ReFantazio', 'metaphor-refantazio', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2679460/header.jpg?t=1764776325', NULL, 'After his assassination, the will of the late king decrees the next monarch to be elected by the people. Forge bonds and win over a kingdom divided in this award-winning fantasy RPG with turn-based and action combat, party customization with powerful Archetypes, and hours of exploration.', '{\"genre\": \"Action, Adventure, RPG\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/2_7jdpHzpZw\", \"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1MH4y1c7Yq\"}, \"demo_url\": \"steam://install/3130330\", \"platform\": \"\", \"developer\": \"ATLUS\", \"demo_available\": true}', 'https://www.youtube.com/embed/2_7jdpHzpZw', NULL, 'https://store.steampowered.com/app/2679460/', NULL, 'manual', 1, '2026-05-27 18:06:01', '2026-05-27 20:07:55', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (8, 'game', 'S.T.A.L.K.E.R. 2', 'stalker-2', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1643320/3e525c6969728ec1641c5834e660472357fcd4cf/header.jpg?t=1776173087', NULL, 'Discover the vast Chornobyl Exclusion Zone full of dangerous enemies, deadly anomalies and powerful artifacts. Unveil your own epic story as you make your way to the Heart of Chornobyl. Make your choices wisely, as they will determine your fate in the end.', '{\"genre\": \"Action, Adventure, RPG\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/SiECiie1CbI\", \"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1y8411m7Jk\"}, \"platform\": \"\", \"developer\": \"GSC Game World\", \"demo_available\": false}', 'https://www.youtube.com/embed/SiECiie1CbI', NULL, 'https://store.steampowered.com/app/1643320/', NULL, 'manual', 1, '2026-05-27 18:06:01', '2026-05-27 20:07:55', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (11, 'boardgame', '《沙丘：帝国》Dune: Imperium', '《沙丘：帝国》Dune: Imperium', '/uploads/10ea5651-fff6-427f-84dc-49026f880c8c.webp', '/uploads/21d773ff-c440-4a0b-b758-2cf2f710eb2c.webp', '《沙丘：帝国》是由旅法师营地代理，美国DWD根据沙丘IP和传奇影业电影《沙丘》而制作的1-4人桌面游戏，游戏将卡组构筑和工人放置两种游戏模式创新地结合在一起带来了更多的策略成分。', '{\"videos\": {\"youtube\": \"\", \"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1j5411K7FU\"}, \"weight\": 3, \"players\": \"1-4\", \"playtime\": \"60-120min\", \"rule_text\": \" 勘误：力标记应为战斗力标记，实体说明书已修正。\", \"rule_images\": \"/uploads/0d295f69-ea84-4aa9-addc-bfab211fb6ae.jpeg,/uploads/7ddea1cc-c854-4b0b-b1e6-8f3fc57551a0.jpeg,/uploads/8217b935-782c-4fab-9600-d82b32ffa9bb.jpeg,/uploads/eaa61a24-2c31-4420-aeb3-edc73a7b2da1.jpeg,/uploads/3263b2e9-9e31-4cea-8ddd-4faa1877a75a.jpeg,/uploads/743dd289-289e-4271-a94d-cef54f06fd3b.jpeg,/uploads/464e7490-79b7-492d-83b1-2a779ceaf1a4.jpeg,/uploads/53149bd5-2952-4d3b-bb48-1b02806b259d.jpeg,/uploads/07a0df33-0e28-44dc-ae5f-59e211f10e04.jpeg,/uploads/5c951995-bc04-4f9f-b250-f0595a743af0.jpeg,/uploads/2afc7321-a337-44d1-8f54-cf4d31bb2171.jpeg,/uploads/b220b54e-2b67-4203-9376-97851c761cb9.jpeg,/uploads/d752f616-1ef6-4a4e-bc30-e37698ad98f3.jpeg,/uploads/9cf3d2e9-78ea-494f-b1d4-4225d9ee58d9.jpeg,/uploads/d78be0a9-b82a-4eeb-8a99-da53224ba3ec.jpeg,/uploads/8cc2850e-02a3-42c2-aad4-d1af3bb117ab.jpeg\"}', 'https://www.bilibili.com/video/BV1j5411K7FU/', '/uploads/21d773ff-c440-4a0b-b758-2cf2f710eb2c.webp', 'https://iyingdi.com/tz/post/2355551', '', '旅法师营地', 1, '2026-05-27 18:06:01', '2026-06-09 06:57:30', 0);
