INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (49, 'game', 'Buckshot Roulette', 'buckshot-roulette', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2835570/header.jpg?t=1779135850', NULL, 'Play Russian roulette with a 12-gauge shotgun. Four enter. One leaves. Roll the dice with your life. Good luck!', '{\"genre\": \"Action, Indie, Simulation\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/XpU9Wk6uYQ4\", \"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1jC411z7JW\"}, \"demo_url\": \"https://mikeklubnika.itch.io/buckshot-roulette\", \"platform\": \"\", \"developer\": \"Mike Klubnika\", \"demo_available\": true}', 'https://www.youtube.com/embed/XpU9Wk6uYQ4', NULL, 'https://store.steampowered.com/app/2835570/', NULL, 'manual', 1, '2026-05-27 19:23:13', '2026-06-03 16:33:28', 2);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (54, 'movie', '奥本海默', 'tmdb-872585', 'https://image.tmdb.org/t/p/w500/a6v21Mgz2w6OQL7ezkQxGbGA92W.jpg', 'https://image.tmdb.org/t/p/w1280/neeNHeXjMF5fXoCJRsOmkNGC7q.jpg', '亲临这部震撼全球的现象级巨制。克里斯托弗·诺兰编剧并执导的本片带领观众深入物理学家J·罗伯特·奥本海默（基里安·墨菲 饰）的内心世界，他在曼哈顿计划中的开创性工作催生了世界上第一颗原子弹。这场无与伦比的银幕盛宴汇聚全明星阵容，包括艾米莉·布朗特、奥斯卡奖得主马特·达蒙、奥斯卡奖提名者小罗伯特·唐尼、奥斯卡奖提名者弗洛伦丝·皮尤、乔什·哈奈特，以及奥斯卡奖得主凯西·阿弗莱克、拉米·马雷克与肯尼思·布拉纳。[环球影业]', '{\"year\": 2023, \"genre\": \"剧情, 历史\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/hlZO437mwXQ\", \"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1vh41157r8\"}, \"trailer\": \"https://www.youtube.com/embed/hlZO437mwXQ\", \"director\": \"克里斯托弗·诺兰\", \"duration\": \"181min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/872585', '872585', 'tmdb', 1, '2026-05-27 21:06:00', '2026-05-27 21:11:44', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (74, 'movie', '沙丘2', 'tmdb-693134', 'https://image.tmdb.org/t/p/w500/9uaCR4HEZqxUqgORq0uZqTNm43G.jpg', 'https://image.tmdb.org/t/p/w1280/eZ239CUp1d6OryZEBPnO2n87gMG.jpg', '《沙丘2》承接第一部剧情，讲述保罗·厄崔迪（提莫西·查拉梅 Timothée Chalamet 饰）被帕迪沙皇帝和哈克南人联手灭族后，在厄拉科斯星球遇到弗雷曼女战士契妮（赞达亚 Zendaya 饰）以及加入弗雷曼人后展开的传奇旅程。保罗与让他家破人亡的阴谋家们开战，同时面临着一生所爱与已知宇宙命运的两难选择。', '{\"year\": 2024, \"genre\": \"科幻, 冒险\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/StUhbus2_N4\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/StUhbus2_N4\", \"director\": \"丹尼斯·维伦纽瓦\", \"duration\": \"166min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/693134', '693134', 'tmdb', 1, '2026-05-27 21:06:01', '2026-05-27 21:12:37', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (75, 'movie', '你想活出怎样的人生', 'tmdb-508883', 'https://image.tmdb.org/t/p/w500/l4aHizcnMzqQrP39caBatIX7IY3.jpg', 'https://image.tmdb.org/t/p/w1280/a0GM57AnJtNi7lMOCamniiyV10W.jpg', '少年牧真人（山时聪真 配音）的母亲葬身火海后，他随父亲牧胜一（木村拓哉 配音）与继母夏子（木村佳乃 配音）组成新家庭。深陷悲伤的真人阴郁孤僻，难以融入新环境。一次意外，他跟随一只会说话的苍鹭（菅田将晖 配音）闯入废弃的神秘塔楼，却不料进入了奇幻的“亡灵世界”，开始了一场不可思议的冒险……影片片名致敬了小说家吉野源三郎在1937年发表的同名小说，但电影故事由宫崎骏原创。', '{\"year\": 2023, \"genre\": \"动画, 奇幻, 剧情\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/vS4LJdgA0pE\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/vS4LJdgA0pE\", \"director\": \"宫崎骏\", \"duration\": \"124min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/508883', '508883', 'tmdb', 1, '2026-05-27 21:06:02', '2026-05-27 21:12:39', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (76, 'movie', '超级马力欧兄弟大电影', 'tmdb-502356', 'https://image.tmdb.org/t/p/w500/kvxefG51enXTQQwlyn09qorJb4s.jpg', 'https://image.tmdb.org/t/p/w1280/9n2tJBplPbgR2ca05hS5CKXwP2c.jpg', '马力欧（克里斯·帕拉特 Chris Pratt 配音）和路易吉（查理·戴 Charlie Day 饰）是生活在布鲁克林的两名水管工，他们刚刚成立了自己的小公司，但很显然，他们的家人并不完全支持兄弟两人的这份事业。某日，在工作中，马力欧和路易吉被水管吸入到了一个光怪陆离的世界之中，两人在旅途中被迫分开，马力欧来到了由碧姬公主（安雅·泰勒-乔伊 Anya Taylor-Joy 配音）统治的蘑菇王国，而路易吉则不幸的被传送到了由酷霸王（杰克·布莱克 Jack Black 配音）统治的库巴王国。此时，酷霸王正准备大举进攻蘑菇国，掳走公主并和她结婚，在这个节骨眼上，马力欧的出现带给了碧姬公主希望，她带着马力欧来到了丛林王国，请求那里的国王和王子（塞斯·罗根 Seth Aaron Rogen 饰）的支援。', '{\"year\": 2023, \"genre\": \"家庭, 喜剧, 冒险, 奇幻, 动画\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/aNO17No4V8o\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/aNO17No4V8o\", \"director\": \"亚伦·霍瓦特\", \"duration\": \"92min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/502356', '502356', 'tmdb', 1, '2026-05-27 21:06:07', '2026-05-27 21:12:42', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (83, 'movie', '星际穿越', 'movie-星际穿越', 'https://image.tmdb.org/t/p/w500/c35Vwd9rmMQfaEJuUrJRF3LZWJX.jpg', 'https://image.tmdb.org/t/p/w1280/5XNQBqnBwPA9yT0jZ0p3s8bbLh0.jpg', '近未来的地球黄沙遍野，小麦、秋葵等基础农作物相继因枯萎病灭绝，人类不再像从前那样仰望星空，放纵想象力和灵感的迸发，而是每日在沙尘暴的肆虐下倒数着所剩不多的光景。在家务农的前NASA宇航员库珀接连在女儿墨菲的书房发现奇怪的重力场现象，随即得知在某个未知区域内前NASA成员仍秘密进行一个拯救人类的计划。多年以前土星附近出现神秘虫洞，NASA借机将数名宇航员派遣到遥远的星系寻找适合居住的星球。在布兰德教授的劝说下，库珀忍痛告别了女儿，和其他三名专家教授女儿艾米莉亚·布兰德、罗米利、多伊尔搭乘宇宙飞船前往目前已知的最有希望的三颗星球考察。他们穿越遥远的星系银河，感受了一小时七年光阴的沧海桑田，窥见了未知星球和黑洞的壮伟与神秘。在浩瀚宇宙的绝望而孤独角落，总有一份超越了时空的笃定情怀将他们紧紧相连……', '{\"year\": 2014, \"genre\": \"冒险, 剧情, 科幻\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/1GmqkGScOVY\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/1GmqkGScOVY\", \"director\": \"克里斯托弗·诺兰\", \"duration\": \"169min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/157336', '157336', 'tmdb', 1, '2026-05-27 21:08:41', '2026-05-27 21:13:01', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (84, 'movie', '盗梦空间', 'movie-盗梦空间', 'https://image.tmdb.org/t/p/w500/89W962aAnPS3N3BdKgy2BvUhnCh.jpg', 'https://image.tmdb.org/t/p/w1280/8ZTVqvKDQ8emSGUEMjsS4yHAwrp.jpg', '道姆·柯布与同事阿瑟和纳什在一次针对日本能源大亨齐藤（渡边谦 饰）的盗梦行动中失败，反被齐藤利用。齐藤威逼利诱因遭通缉而流亡海外的柯布帮他拆分他竞争对手的公司，采取极端措施在其唯一继承人罗伯特·费希尔的深层潜意识中种下放弃家族公司、自立门户的想法。为了重返美国，柯布偷偷求助于岳父迈尔斯，吸收了年轻的梦境设计师艾里阿德妮、梦境演员艾姆斯和药剂师约瑟夫加入行动。在一层层递进的梦境中，柯布不仅要对付费希尔潜意识的本能反抗，还必须直面已逝妻子梅尔的处处破坏，实际情况远比预想危险得多……', '{\"year\": 2010, \"genre\": \"动作, 科幻, 冒险\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/8dTeGRLGqNE\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/8dTeGRLGqNE\", \"director\": \"克里斯托弗·诺兰\", \"duration\": \"148min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/27205', '27205', 'tmdb', 1, '2026-05-27 21:08:46', '2026-05-28 09:20:04', 3);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (86, 'movie', '蜘蛛侠：纵横宇宙', 'movie-蜘蛛侠：纵横宇宙', 'https://image.tmdb.org/t/p/w500/rilpPMoF4LbKcBPb4omiqm7Zjw0.jpg', 'https://image.tmdb.org/t/p/w1280/9xfDWXAUbFXQK585JvByT5pEAhe.jpg', '荣获奥斯卡奖的蜘蛛侠平行宇宙传奇迎来全新篇章。在这段史诗级冒险中，布鲁克林的全职邻家英雄蜘蛛侠迈尔斯·莫拉莱斯将穿越多元宇宙，与格温·史黛西及全新蜘蛛侠团队集结成军，直面前所未见的强大反派。[索尼影业]', '{\"year\": 2023, \"genre\": \"动画, 动作, 冒险, 科幻\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/EQQcxYtmvGw\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/EQQcxYtmvGw\", \"director\": \"肯普·鲍尔斯\", \"duration\": \"140min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/569094', '569094', 'tmdb', 1, '2026-05-27 21:08:57', '2026-05-28 09:20:04', 4);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (87, 'movie', '阿凡达：水之道', 'movie-阿凡达：水之道', 'https://image.tmdb.org/t/p/w500/az6FndKaR11uuxnRQucKJ2mmglg.jpg', 'https://image.tmdb.org/t/p/w1280/kJsPVzdyBrYHLomuNv5SJDXUQ2f.jpg', '十多年过去了，曾经截瘫的前海军士兵杰克·萨利（萨姆·沃辛顿饰）永久变身为拥有地球人基因和纳威人基因的“阿凡达”，并与奥马蒂卡亚部落的族长之女奈蒂莉（佐伊·索尔达娜饰）结为夫妇。杰克已经完全适应了他的新身体和族长的身份，并和奈蒂莉有了三个孩子，还收养了格蕾丝留下的女儿琪莉（西格妮·韦弗饰）。四个孩子里，老大纳特亚姆（杰米·福雷特斯饰）最为懂事听话，也很会照顾弟弟妹妹；老二琪莉（西格妮·韦弗 饰）因为不知道自己的父亲是谁，有些敏感；老三洛克（布里坦·道尔顿 饰）酷爱冒险，是家里的闯祸精；最小的妹妹图克（特里尼蒂·布利斯 饰）总是黏着哥哥姐姐们。四人跟人类留下的孤儿“蜘蛛”（杰克·尚皮永饰）是形影不离的好朋友。 原本，将地球人赶走后，杰克一家与族人过上了田园牧歌般的生活。然而，原本死去的迈尔斯·夸里奇上校（史蒂芬·朗饰）化身阿凡达重新归来，一心要找杰克和奈蒂莉复仇。为了族人的安危，也为了保护孩子，杰克决定带着家人离开，前往不易被找到的由罗娜尔（凯特·温斯莱特饰）和特诺瓦里（克利夫·柯蒂斯饰）领导的海洋部落，展开全新的生活。正当一家人经过重重磨合，终于适应以水构筑的新家园时，新的危机也在慢慢靠近。', '{\"year\": 2022, \"genre\": \"动作, 冒险, 科幻\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/xV6KcDEeGbM\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/xV6KcDEeGbM\", \"director\": \"詹姆斯·卡梅隆\", \"duration\": \"193min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/76600', '76600', 'tmdb', 1, '2026-05-27 21:09:02', '2026-05-27 21:09:02', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (88, 'movie', '瞬息全宇宙', 'movie-瞬息全宇宙', 'https://image.tmdb.org/t/p/w500/p8ulGTtp2Syv2U5H32FcWoBQb9v.jpg', 'https://image.tmdb.org/t/p/w1280/ss0Os3uWJfQAENILHZUdX8Tt1OC.jpg', '焦头烂额的移民母亲伊芙琳·王突然接到来自平行宇宙的联络，被告知唯有她能拯救世界。这位看似普通的英雄必须学着掌控自己新获得的力量，在支离破碎的多元宇宙时间线中奋力抗争，以拯救她的家园、家人，以及那个迷失在琐碎生活中的自己。', '{\"year\": 2022, \"genre\": \"动作, 冒险, 科幻\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/uAMsKHaqRfQ\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/uAMsKHaqRfQ\", \"director\": \"丹尼尔·谢纳特\", \"duration\": \"132min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/545611', '545611', 'tmdb', 1, '2026-05-27 21:09:07', '2026-05-27 21:13:06', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (89, 'movie', 'Top Gun: Maverick', 'movie-top-gun-maverick', 'https://image.tmdb.org/t/p/w500/aHniPlfAQykMFhmbUzfn5qtorC7.jpg', 'https://image.tmdb.org/t/p/w1280/AaV1YIdWKnjAIAOe8UUKBFm327v.jpg', '壮志凌云2：独行侠 作为海军顶尖飞行员服役30多年后，皮特·米切尔（代号：“独行侠”）（汤姆·克鲁斯 饰演）决定打破体制的限制，成为一名试飞员接受更大的挑战。当他接到命令，为一项高难度特殊任务训练一群“高空利剑”项目的毕业生时，他遇到了已故的好友兼雷达截获官，代号“笨鹅”的尼克·布拉德肖中尉之子布莱德利·布拉德肖中尉（代号：“公鸡”）。  面对不确定的未来和难以释怀的心魔，独行侠必须战胜内心深处的恐惧。因此，他参与了一项需要巨大牺牲才能完成的任务', '{\"year\": 2022, \"genre\": \"动作, 剧情\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/Klc__shdj88\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/Klc__shdj88\", \"director\": \"约瑟夫·科辛斯基\", \"duration\": \"131min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/361743', '361743', 'tmdb', 1, '2026-05-27 21:09:12', '2026-05-27 21:13:09', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (90, 'movie', '蝙蝠侠：黑暗骑士', 'movie-蝙蝠侠：黑暗骑士', 'https://image.tmdb.org/t/p/w500/xUX0sVHmukGTYLTyqmSF5hpktOU.jpg', 'https://image.tmdb.org/t/p/w1280/cfT29Im5VDvjE0RpyKOSdCKZal7.jpg', '蝙蝠侠在打击犯罪的战争中加大了赌注。在吉姆·戈登警长与地方检察官哈维·丹特的协助下，蝙蝠侠决心清除肆虐哥谭街头的残余犯罪组织。这一联手行动卓有成效，但他们很快发现自己沦为了一场混沌统治的猎物——这场混乱由一位新兴犯罪大师所掀动，惶恐的哥谭市民称他为“小丑”。[华纳兄弟影业]', '{\"year\": 2008, \"genre\": \"动作, 犯罪, 惊悚\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/_PZpmTj1Q8Q\", \"bilibili\": \"\"}, \"director\": \"克里斯托弗·诺兰\", \"duration\": \"152min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/155', '155', 'tmdb', 1, '2026-05-27 21:09:18', '2026-06-09 08:26:14', 1);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (92, 'movie', '泰坦尼克号', 'movie-泰坦尼克号', 'https://image.tmdb.org/t/p/w500/lFYUkUPcFXDzZzSfkiCDsvHIJxj.jpg', 'https://image.tmdb.org/t/p/w1280/xnHVX37XZEp33hhCbYlQFq7ux1J.jpg', '1912年4月10日，号称 “世界工业史上的奇迹”的豪华客轮泰坦尼克号开始了它完工后的首次商业航行，从英国的南安普顿出发驶往美国纽约。富家少女罗丝与母亲及未婚夫卡尔坐上了头等舱；另一边，放荡不羁的少年画家杰克也在码头的一场赌博中赢得了下等舱的船票。罗丝厌倦了上流社会虚伪的生活，不愿嫁给卡尔，打算投海自尽，被杰克救起。很快，美丽活泼的罗丝与英俊开朗的杰克相爱，杰克带罗丝参加下等舱的舞会、为她画像，二人的感情逐渐升温。1912年4月14日，星期天晚上，一个风平浪静的夜晚。泰坦尼克号撞上了冰山，“永不沉没的”泰坦尼克号面临沉船的命运，罗丝和杰克刚萌芽的爱情也将经历生死的考验。', '{\"year\": 1997, \"genre\": \"剧情, 爱情\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/-9iHB2EU6G8\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/-9iHB2EU6G8\", \"director\": \"詹姆斯·卡梅隆\", \"duration\": \"194min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/597', '597', 'tmdb', 1, '2026-05-27 21:09:28', '2026-05-27 21:13:14', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (93, 'movie', '肖申克的救赎', 'movie-肖申克的救赎', 'https://image.tmdb.org/t/p/w500/Aqo8yM5S5ZEdlcyeBBxj7s0vkTf.jpg', 'https://image.tmdb.org/t/p/w1280/zfbjgQE1uSd9wiPTX4VzsLi0rGG.jpg', '安迪·杜佛兰被错判谋杀妻子及其情人，在缅因州肖申克服刑，判处两项无期徒刑接连执行。影片背景设定于1940年代，展现安迪如何在残酷的监狱环境中艰难求生，甚至赢得狱友们的敬重——尤其是与老囚徒“瑞德”·雷丁之间深厚的友谊。', '{\"year\": 1994, \"genre\": \"剧情, 犯罪\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/PLl99DlL6b4\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/PLl99DlL6b4\", \"director\": \"弗兰克·德拉邦特\", \"duration\": \"142min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/278', '278', 'tmdb', 1, '2026-05-27 21:09:34', '2026-05-28 09:20:04', 2);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (95, 'movie', '寄生虫', 'movie-寄生虫', 'https://image.tmdb.org/t/p/w500/nwTQE4vWe6NoFSEgxGu4hO9J4Tv.jpg', 'https://image.tmdb.org/t/p/w1280/TU9NIjwzjoKPwQHoHshkFcQUCG.jpg', '这部定义时代精神的惊世之作，将全球范围内对阶级不平等的审视浓缩为一场流行电影的反叛风暴。奉俊昊导演以这部打破类型桎梏的黑色喜剧惊悚片，奠定了其世界顶尖电影作者的地位。故事聚焦首尔的两个家庭——一户在低洼社区潮湿半地下室里挣扎求生的底层家庭，另一户则居住于可俯瞰城市的现代建筑奇观中尽享奢华。当两家人的命运因危险关系交织在一起时，资本主义的黑暗裂隙以惊人之势被彻底撕裂。影片凭借导演精心构建的戏剧场景、出色的群像演绎与震撼的视觉设计，成为一部技艺卓绝的典范之作。从戛纳到奥斯卡，横扫几乎所有国际至高奖项，更以首部非英语片问鼎最佳影片的历史性突破，宣告韩国新电影已成为不可忽视的世界力量。', '{\"year\": 2019, \"genre\": \"喜剧, 惊悚, 剧情\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/lkA5ifth91k\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/lkA5ifth91k\", \"director\": \"奉俊昊\", \"duration\": \"132min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/496243', '496243', 'tmdb', 1, '2026-05-27 21:10:12', '2026-05-27 21:13:19', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (96, 'movie', '千与千寻', 'movie-千与千寻', 'https://image.tmdb.org/t/p/w500/9oZmkkNlI4Ktx6NTkdpeU525qSc.jpg', 'https://image.tmdb.org/t/p/w1280/dyJvKsNs2KP8qQnAXbRwDjblViy.jpg', '小女孩千寻被困在一个陌生的精灵世界。当她的父母发生神秘变化后，她必须鼓起自己从未发现的勇气，才能解救自己，并将家人带回外面的世界。', '{\"year\": 2001, \"genre\": \"动画, 家庭, 奇幻\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/GAp2_0JJskk\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/GAp2_0JJskk\", \"director\": \"宫崎骏\", \"duration\": \"125min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/129', '129', 'tmdb', 1, '2026-05-27 21:10:14', '2026-05-27 21:13:22', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (98, 'movie', '给阿嬷的情书', 'tmdb-1671548', 'https://image.tmdb.org/t/p/w500/s0sC3hPPX4OobLNfdl2iSs2vtvI.jpg', 'https://image.tmdb.org/t/p/w1280/dzWGnIAjUafpmY57F6vnm44FwWB.jpg', '潮汕阿嬷叶淑柔一直守着平淡的日子，安享晚年。孙子晓伟因债务缠身，瞒着家人远赴泰国，寻找传闻中已成亿万富豪的阿公郑木生。然而，一个令人意外的消息打破了整个家庭的平静：多年来一直通过跨国信件与阿嬷“谈情说爱”诉说思念的人，竟然并非阿嬷的丈夫郑木生。随着晓伟的调查，一个感人的真相被缓缓揭开。', '{\"year\": 2026, \"genre\": \"剧情, 家庭, 喜剧\", \"videos\": {\"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1mZRiBDEQJ\"}, \"trailer\": \"https://www.youtube.com/embed/e9VlQ2XJzTk\", \"director\": \"蓝鸿春\", \"duration\": \"118min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/1671548', '1671548', 'tmdb', 1, '2026-05-28 00:42:23', '2026-05-28 00:42:23', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (99, 'movie', '人鬼情未了', 'tmdb-251', 'https://image.tmdb.org/t/p/w500/zsbgH75dl1YQjHx3bpPlENYHpgw.jpg', 'https://image.tmdb.org/t/p/w1280/6nLdSON3ErniBZTXWG7WRqs5jGz.jpg', '　　年轻的银行职员萨姆（帕特里克•斯威兹）与未婚妻美莉（黛咪•摩尔）相爱极深，在朋友卡尔（托尼•戈德温）的热情帮助下，他们搬进一幢漂亮的公寓，做着结婚前的准备。某晚看戏归来时，他们遭遇持枪歹徒，与歹徒搏斗时，萨姆不幸中枪身亡，美莉悲痛欲绝。  　　萨姆变作幽灵，发现卡尔是导致他死亡的幕后策划，而为了窃取银行里的巨款，他又对美莉展开追求，以便获得萨姆所掌握的密码。为了保护美莉，萨姆常常游荡于她的周围，并渐渐地学会了如何使用力量，但他苦于无法同美莉交流。在能与幽灵沟通的灵媒奥塔的帮助下，他与美莉取得联系，但美莉起初并不相信，直到事实令她感受到萨姆的存在，可是，深深相爱的两人仍无法直接接触和交流。', '{\"year\": 1990, \"genre\": \"奇幻, 爱情, 惊悚\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"杰瑞·扎克\", \"duration\": \"127min\"}', NULL, 'https://image.tmdb.org/t/p/w500/zsbgH75dl1YQjHx3bpPlENYHpgw.jpg', 'https://www.themoviedb.org/movie/251', '251', 'tmdb', 1, '2026-05-28 01:05:12', '2026-05-28 01:05:12', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (101, 'movie', '低俗小说', 'tmdb-680', 'https://image.tmdb.org/t/p/w500/WZW5PCtCbtyKfojdLlPCi89DNx.jpg', 'https://image.tmdb.org/t/p/w1280/suaEOtk1N1sgg2MTM7oZd2cfVp3.jpg', '　《低俗小说》由“文森特和马沙的妻子”、“金表”、“邦妮的处境”三个故事以及影片首尾的序幕和尾声五个部分组成。看似独立的小故事里面，却又有环环相扣的人和事。\r 盗贼“小南瓜”和“小兔子”在早餐店里打劫，却遇上了天大的麻烦——黑社会成员朱尔斯（塞缪尔•杰克逊Samuel L. Jackson饰）和文森特（约翰•特拉沃尔塔John Travolta饰）在店内用餐，可谓天外有天。二人是否会放过两名小盗贼？\r 而文森特是黑社会大哥马沙•华莱士（文•瑞姆斯Ving Rhames饰）的手下，马沙下命令让他陪妻子一个晚上，明知如有雷池必死无疑，但面对马沙妻子美艳诱惑，文森特该怎么办。\r 文森特的故事还没完，拳击手布奇（布鲁斯•威利斯Bruce Willis饰）的出现将令他的人生从此改变。布奇有一块祖传金表，就是因为这块金表，他和马沙分享了一个耻辱的秘密。\r 故事环状结构，回到开端。朱尔斯在小盗贼面前诵读圣经，表示对杀人的厌倦和感悟。什么事件令他如此转变？“邦妮的处境”中就有答案。', '{\"year\": 1994, \"genre\": \"惊悚, 犯罪, 喜剧\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/tGpTpVyI_OQ\", \"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"昆汀·塔伦蒂诺\", \"duration\": \"154min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/680', '680', 'tmdb', 1, '2026-05-28 01:15:31', '2026-05-28 01:15:31', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (110, 'movie', '科比的缪斯', 'tmdb-300761', 'https://image.tmdb.org/t/p/w500/p9jpl4brgiymBSBod61hAV7ONKn.jpg', '/uploads/3aa7909b-8a60-467b-9817-4017e04587dc.webp', '　　这部长篇记录片背标邦威记录科比的生活，灵感及遇到的挑战，也为他下一季重回NBA赛季奠定了基础。这部片子还会聚焦在科比在其职业生涯内所取得的成功及面临的挑战，让大家看到另一面的篮球明星。科比在片中也会谈到自己对于运动生涯结束后的规划，尽管没有给出详细的例子，但是Showt ime节目表示科比的“个人成长经历”也会着重被讲述。\r 　　“《科比·布莱恩特的缪斯》将提供给观众一个全面的职业运动员，一个已经超越了自身职业并成为了一个标志性人物的运动员”。美国娱乐时间电视台执行副总裁埃斯皮诺萨表示，“我们很高兴，科比给了我们这个前所未有的访问，这将让我们的观众见证一次NBA的最伟大球员之一生命中这样一个充满挑战的时期”。\r 　　科比·布莱恩特，18次进入NBA全明星赛，五次进入NBA总冠军赛，因为左膝受伤而缺席了2013-14赛季。', '{\"year\": 2015, \"genre\": \"纪录, 电视电影, 体育\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/8dga5amhKnQ\", \"bilibili\": \"\"}, \"director\": \"Gotham Chopra\", \"duration\": \"83min\"}', '', NULL, 'https://www.youtube.com/embed/8dga5amhKnQ', '300761', 'tmdb', 1, '2026-05-28 01:46:39', '2026-05-28 09:44:14', 0);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (285, 'anime', '葬送的芙莉莲', 'sousou-no-frieren', 'https://picsum.photos/seed/frieren/600/400', NULL, '勇者一行击败魔王后，精灵魔法使芙莉莲踏上理解人类情感的旅程。2023 年度动画天花板，温柔而深沉。', '{\"year\": 2023, \"genre\": \"奇幻, 治愈\", \"origin\": \"日漫\", \"studio\": \"MADHOUSE\", \"videos\": {\"bilibili\": \"//player.bilibili.com/player.html?bvid=BV1uN411n7zt\"}}', '//player.bilibili.com/player.html?bvid=BV1uN411n7zt', NULL, NULL, NULL, 'manual', 1, '2026-05-28 10:18:17', '2026-05-28 13:16:28', 1);
