INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (295, 'anime', '镇魂街', 'anilist-99707', 'https://s4.anilist.co/file/anilistcdn/media/anime/cover/medium/bx99707-VpuVWgyNltUV.png', '/uploads/5fbcdba7-b4f8-4572-80e9-17d77c5d4749.jpg', 'Based on the Chinese Manhua. Requiem Street, where evil spirits are attracted to in order to destroy them. A place where spirits and humans co-exist, not all humans can enter Requiem Street. Only those rare-soul users with guardian spirits can enter. Xia Ling was just a normal university intern, but a meeting by chance changes her ordinary life... In this world full of evil spirits, can you cooperate with your guardian spirit in order to survive?\n', '{\"year\": \"\", \"genre\": \"Action, Drama, Supernatural\", \"origin\": \"国漫\", \"studio\": \"L² Studio\", \"videos\": {\"youtube\": \"\", \"bilibili\": \"\"}, \"episodes\": 24}', NULL, NULL, 'https://anilist.co/anime/99707', '99707', 'anilist', 1, '2026-05-28 10:45:34', '2026-06-09 06:05:53', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (302, 'movie', '猫和老鼠', 'tmdb-587807', 'https://image.tmdb.org/t/p/w500/54ngjKpxAxht9PsbXT6DgJsYvyq.jpg', 'https://image.tmdb.org/t/p/w1280/69USXLJEXcgMzlhZi7bmaCORxHn.jpg', '“超杀女”科洛·莫瑞兹饰演的少女凯拉刚刚入职豪华大酒店，就碰上了叫人头疼的难题——杰瑞竟然想在酒店里定居，令酒店最近承接的世纪婚礼岌岌可危。于是，汤姆被凯拉雇佣成为酒店员工，目的是赶走杰瑞，这对欢喜冤家就此展开了一场你追我赶的爆笑喜剧。', '{\"year\": 2021, \"genre\": \"喜剧, 家庭, 动画\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"蒂姆·斯道瑞\", \"duration\": \"101min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/587807', '587807', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (303, 'movie', '猫和老鼠：西部大冒险', 'tmdb-892153', 'https://image.tmdb.org/t/p/w500/xg6tfdV0EkERagRLteGSNyetWZA.jpg', 'https://image.tmdb.org/t/p/w1280/q1NXVYTqSStNQsnKrCvtU6NPzEk.jpg', '这部电影在荒野的西部发现了猫和老鼠二人组，他们在那里帮助从一个恶棍手中拯救了一个牧场。竞争对手联手帮助一个女牛仔和她的兄弟从贪婪的土地掠夺者手中拯救他们的家园。杰瑞的三个早熟的侄子也加入了行动，汤姆围捕了一队土拨鼠。', '{\"year\": 2022, \"genre\": \"动画, 喜剧, 家庭, 西部\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"Darrell Van Citters\", \"duration\": \"75min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/892153', '892153', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (304, 'movie', '猫和老鼠电影版', 'tmdb-22582', 'https://image.tmdb.org/t/p/w500/k68ZB5trRKcEJSQdPiY6jtxVq14.jpg', 'https://image.tmdb.org/t/p/w1280/7x9IsfdRlYXWyy817neZntOM0DN.jpg', '萝苹原以为自己是位孤儿，受不了姑婆的虐待逃离家里。一心前往与父亲的小木屋在街上流浪遇到一对毛和老鼠汤姆和杰瑞患难见真情.他们从原来的排斥到后来的携手合作帮萝苹找到了父亲。', '{\"year\": 1993, \"genre\": \"动画, 喜剧, 家庭\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"Phil Roman\", \"duration\": \"84min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/22582', '22582', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (306, 'movie', '猫和老鼠：飙风天王', 'tmdb-42246', 'https://image.tmdb.org/t/p/w500/kJiUWgcbCqD9GZCsJZYmGDU17sw.jpg', 'https://image.tmdb.org/t/p/w1280/bXILbW1i0WRShd6s4LfLKdJM6zm.jpg', '　　比赛开始！全球人气最旺的卡通猫鼠搭档，也因此被扫地出门…因为他们专门坏事！他们下一步是实境电视节目，他们报名超级大赛车，第一名的奖品是一栋豪宅。汤姆猫与杰米鼠不按牌理出牌的脱线演出，让该节目的收视率节节高升高，电视台的高层也因此乐不可支。我们敢拍胸脯保证，若您看了这部疯狂搞笑的卡通片也一样笑得合不拢嘴。在这部老少咸宜疯狂搞笑的卡通片中，所有的观众都是赢家。', '{\"year\": 2005, \"genre\": \"动画, 喜剧, 家庭, 动作\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"Bill Kopp\", \"duration\": \"75min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/42246', '42246', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (307, 'movie', '猫和老鼠：海盗寻宝', 'tmdb-60293', 'https://image.tmdb.org/t/p/w500/xEIqCPw372pdkf50C0bCT66HOJy.jpg', 'https://image.tmdb.org/t/p/w1280/sTTQggCcbkf8KWmdYDx0kIhEXxI.jpg', '在浩瀚无边的国际公海上，红海盗罗恩率领手下横行霸道。懒惰的汤姆和机敏的杰瑞也在这艘船上，一番例行的追逐吵闹过后，汤姆捡到一支漂流瓶，并意外在里面发现一张藏宝图。里面记录了西班牙船队金银财宝的秘密，同时也藏着可怕的诅咒：如果不在天黑前把地图放回漂流瓶重新扔回大海的话，那么将会遭遇可怕的噩运。慌张的汤姆正要将其放回，谁知地图却被红海盗抢走。当然，这也引发了罗恩和兄弟蓝海盗鲍勃的争斗。刀光剑影，你来我往，混乱的拼杀过后，他们错过了太阳落山的时刻，结果海盗船被西班牙骷髅幽灵霸占。几经辗转，汤姆、杰瑞终于随红海盗他们来到藏宝的小岛，并见到早已失踪的紫海盗，冒险仍在继续……', '{\"year\": 2006, \"genre\": \"动画, 喜剧, 家庭, 冒险\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"Scott Jeralds\", \"duration\": \"74min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/60293', '60293', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (308, 'movie', '猫和老鼠：魔法戒指', 'tmdb-14787', 'https://image.tmdb.org/t/p/w500/fF6I48WGKktHfGYYSVKPTVildWE.jpg', 'https://image.tmdb.org/t/p/w1280/dS9wDDuVyiq5pQRD8ab4JcM6Doy.jpg', '猫咪汤姆和老鼠杰瑞是一对欢喜冤家，他们常常为了鸡毛蒜皮的小事闹得天翻地覆。主人制造出了一只魔戒，命令汤姆日夜看管不得有误。谁料调皮的杰瑞偷来魔戒，还把它当成皇冠戴在头上。这下，可把汤姆急坏了，发誓在主人发现前找回魔戒。虽然在魔戒的帮助下杰瑞躲过了汤姆一次次的“追捕”，可是汤姆怎肯轻易罢休。一场猫鼠大战就此开演……', '{\"year\": 2002, \"genre\": \"动画, 喜剧, 家庭, 奇幻\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"James T. Walker\", \"duration\": \"62min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/14787', '14787', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (312, 'movie', '猫和老鼠：间谍使命', 'tmdb-343977', 'https://image.tmdb.org/t/p/w500/5tCVbv0OlEdhBSnK0f7xO39uLwn.jpg', 'https://image.tmdb.org/t/p/w1280/vOjJf8avUb0yZbnpUBYq3y13wYj.jpg', '2015全新动感的华纳大动画电影——汤姆和杰瑞之间谍任务。任何年龄的汤姆和杰瑞迷都不会想错过和汤姆和杰瑞一起去冒险，一起去拯救世界，一起踏上危险的间谍任务。', '{\"year\": 2015, \"genre\": \"动画, 喜剧, 家庭\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"Spike Brandt\", \"duration\": \"73min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/343977', '343977', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (314, 'movie', '猫和老鼠：回到奥兹', 'tmdb-403510', 'https://image.tmdb.org/t/p/w500/kilE7AJV1gEecTzW51XNi8YHBvs.jpg', 'https://image.tmdb.org/t/p/w1280/6cXwjZTHRSFTgEvNdnKUw93Pnv6.jpg', '随着西方的邪恶女巫现在从奥兹征服，汤姆和杰瑞以及多萝西回到了堪萨斯！ 但是不久之后，一个全新的恶棍从神奇的土地 - 侏儒王下面浮现出来！ 抓住好女巫后，Gnome King和他的军队在整个Oz中肆虐，只需要一件物品来控制翡翠城，Dorothy的红宝石拖鞋！ 这取决于我们最喜欢的猫捉老鼠二人组合，回到Oz并拯救他们喜爱的土地。 在魔法之旅中，带着多萝西，托托，稻草人，铁皮人和狮子一起走向天空。 当他们在黄砖路上遭遇全新的恐怖和恶作剧时，笑声和冒险将会咆哮，因为我们不再在堪萨斯州了！“', '{\"year\": 2016, \"genre\": \"动画, 喜剧, 家庭, 奇幻, 冒险\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"Spike Brandt\", \"duration\": \"81min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/403510', '403510', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (318, 'movie', '猫和老鼠：迷失之龙', 'tmdb-287233', 'https://image.tmdb.org/t/p/w500/s2Tegfa5IOUkFx988FgTFZth189.jpg', 'https://image.tmdb.org/t/p/w1280/7Y2hqJteEvE5DD0j99QTXqF9MZ8.jpg', '中世纪一个聚集着精灵的小山村，正义的魔法师卡尔多夫（吉姆·库宁斯 Jim Cummings 配音）驱逐了邪恶而法术高强的女巫德里泽达（薇姬·刘易斯 Vicki Lewis 配音）。德里泽达无法匹敌，恨恨逃走，而她那不谙世事、单纯善良的侄女雅典娜（凯莉·斯泰堡丝 Kelly Stables 配音）则获准留了下来。在此期间，雅典娜还收养了小猫汤姆和老鼠杰瑞。雅典娜敏感的身份以及经常惹祸的猫和老鼠，让女孩一直遭受精灵们的歧视。这一天，汤姆和杰瑞偶然在河边拣到一枚龙蛋，这是之前德里泽达的笨蛋手下们不小心弄丢的，有了它德里泽达就可以用可怕的法术报复驱逐她的精灵们。不久，可爱的绿色小龙孵化出来，而久违的灾难也正向精灵村靠近……', '{\"year\": 2014, \"genre\": \"动画, 喜剧, 家庭, 奇幻\", \"videos\": {\"bilibili\": \"//player.bilibili.com/player.html?bvid=BV14E3tzPEYK\"}, \"director\": \"Spike Brandt\", \"duration\": \"57min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/287233', '287233', 'tmdb', 1, '2026-05-28 11:10:17', '2026-05-28 11:19:13', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (319, 'movie', '猫和老鼠：遇见福尔摩斯', 'tmdb-43956', 'https://image.tmdb.org/t/p/w500/8YLgPSsiDrZMO4yxycMZNcdE5iW.jpg', 'https://image.tmdb.org/t/p/w1280/8rrUYhHEq3KKWP0kZjl0OaBm3D2.jpg', '本片讲述了随着钻石的神秘失踪，伦敦警方组织了很多侦探去查找罪犯，汤姆和杰瑞就是一对组合。棘手的案件让这对猫鼠痛苦不堪，只能寻求世界上最棒的侦探的帮助，他就是夏洛克·福尔摩斯先生。', '{\"year\": 2010, \"genre\": \"动画, 喜剧, 悬疑, 家庭\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"Spike Brandt\", \"duration\": \"49min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/43956', '43956', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (320, 'movie', '猫和老鼠：绿野仙踪', 'tmdb-72972', 'https://image.tmdb.org/t/p/w500/gFlwbp47uh6F1p203RQOaxYThzX.jpg', 'https://image.tmdb.org/t/p/w1280/uScjropoUuhfTP7O2U7h8VJYELQ.jpg', '在远离大都会的西部荒野小镇，可爱少女桃乐丝（格蕾·德丽斯勒 Grey DeLisle 配音）和亨利叔叔（Stephen Root 配音）还有艾姆婶婶（Frances Conroy 配音）生活在一起。有些阴霾的日子里，她的心情无比失落，因为严厉的治安官高驰小姐要将她最爱的小狗托托带走。关键时刻，多亏了汤姆和杰瑞这对冤家搭档出手才总算救回托托。谁知好景不长，猛烈的龙卷风席卷小镇，桃乐丝家的房子被卷上空中，随后落在一个陌生神秘但百花盛开的美丽所在。倒霉的汤姆和杰瑞也一同到来，他们见到了小矮鼠泰菲（Joe Alaskey 配音）。泰菲讲述了众所周知的房子压死东方女巫以及西方女巫企图抢走桃乐丝那双红宝石鞋的故事。  　　在此之后，他们随同泰菲追随桃乐丝的脚步，踏上了寻找奥兹巫师的惊险之旅……', '{\"year\": 2011, \"genre\": \"动画, 喜剧, 冒险, 家庭, 奇幻\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"Spike Brandt\", \"duration\": \"59min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/72972', '72972', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (321, 'movie', '猫和老鼠：雪人国大冒险', 'tmdb-1018403', 'https://image.tmdb.org/t/p/w500/vFYfSu1QmXVE6Ls7kJhiKeK100q.jpg', 'https://image.tmdb.org/t/p/w1280/hgKkCRQT9HhHJ9NKPQKnF1N5eGL.jpg', '是时候与汤姆和杰瑞一起发现圣诞节的精神了！在一个神奇的冬季环境中，杰瑞和他的侄子塔菲用雪做了一只老鼠，它奇迹般地开始过自己的生活！为了保护他们的新朋友，他们命名为拉里，为了免受解冻，塔菲和杰瑞必须将他运送到童话般的雪人村。在这一切混乱中，汤姆和阴险的双维博士出现了，他们对拉里有自己的计划。准备好进行一次难忘的冒险，充满雪，歌曲，动作和欢笑以及节日气氛。', '{\"year\": 2022, \"genre\": \"动画, 家庭, 喜剧, 冒险\", \"videos\": {\"bilibili\": \"\"}, \"trailer\": \"\", \"director\": \"Darrell Van Citters\", \"duration\": \"76min\"}', NULL, NULL, 'https://www.themoviedb.org/movie/1018403', '1018403', 'tmdb', 0, '2026-05-28 11:10:17', '2026-05-28 11:10:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (323, 'anime', '猫和老鼠', 'tmdb-tv-7842', 'https://image.tmdb.org/t/p/w500/gxuenxLwJgRPZjQiBeUmbS3DeKt.jpg', 'https://image.tmdb.org/t/p/w1280/hMiHGRISlUk58Ec3Cz3sg6nIcIR.jpg', '1975年，《猫和老鼠》与“猫和老鼠之父”汉纳和巴伯拉重逢，于每个星期六上午准时播放《猫和老鼠（1975）》（Tom and Jerry Show）。这48个七分钟的短片常与《葡萄猩》（Grape Ape）《牧狗》（Mumbly）一同在1975年9月3日到1977年9月6日间的ABC星期六早晨时段播放，《猫和老鼠》（现在有了一个红色的领结），为了满足儿童观看电视的要求，汉纳巴伯拉不得已放弃了猫和老鼠追逐打闹的场面，让猫和老鼠成为了好朋友。《猫和老鼠（1975）》（Tom and Jerry Show）目前仍在加拿大特律通（Teletoon）电视频道播放。而1975年的银屏格式，在新的《猫和老鼠（1975）》中已不再使用。', '{\"year\": 1975, \"genre\": \"儿童, 动画, 家庭, 喜剧\", \"studio\": \"威廉·汉纳\", \"videos\": {\"bilibili\": \"\"}, \"network\": \"ABC\", \"seasons\": 1, \"trailer\": \"\", \"episodes\": 48}', NULL, NULL, 'https://www.themoviedb.org/tv/7842', '7842', 'tmdb', 0, '2026-05-28 11:10:59', '2026-05-28 11:10:59', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (326, 'anime', '凡人修仙传', 'tmdb-tv-106449', 'https://image.tmdb.org/t/p/w500/i6SYuRHPtODpZ8VX9ql21nj0tDq.jpg', 'https://image.tmdb.org/t/p/w1280/8NIvQY34tNPc4txNeym2zEYk9ek.jpg', '平凡少年韩立出生贫困，为了让家人过上更好的生活，自愿前去七玄门参加入门考核，最终被墨大夫收入门下。墨大夫一开始对韩立悉心培养、传授医术，让韩立对他非常感激，但随着一同入门的弟子张铁失踪，韩立才发现了墨大夫的真面目。墨大夫试图夺舍韩立，最终却被韩立反杀。通过墨大夫的遗书韩立得知了一个全新世界：修仙界的存在。在帮助七玄门抵御外敌之后，韩立离开了七玄门，前去墨大夫的家中寻找暖阳宝玉解毒，并帮助墨家人打败了敌人。通过墨大夫之女墨彩环的口中得知太南小会地址，韩立为追寻修仙人的足迹决定前往太南小会，拜别家人后，韩立来到太南谷，结识了一众修仙人士，正式展开了自己的修仙之旅。', '{\"year\": 2020, \"genre\": \"动画, 动作冒险, Sci-Fi & Fantasy\", \"studio\": \"\", \"videos\": {\"bilibili\": \"\"}, \"network\": \"bilibili\", \"seasons\": 1, \"trailer\": \"https://www.youtube.com/embed/QNdDFy_b9OA\", \"episodes\": 178}', NULL, NULL, 'https://www.themoviedb.org/tv/106449', '106449', 'tmdb', 1, '2026-05-28 11:11:17', '2026-05-28 11:11:17', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (336, 'boardgame', '飞行棋', 'Plane', '', '', '经典传统小游戏，飞行棋', '{\"genre\": \"\", \"videos\": {\"youtube\": \"\", \"bilibili\": \"\"}, \"demo_url\": \"\", \"platform\": \"\", \"developer\": \"\", \"demo_available\": false}', '', '', '', '', 'manual', 1, '2026-05-28 12:25:05', '2026-05-28 12:25:05', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (337, 'anime', '中国奇谭', 'tmdb-tv-139162', 'https://image.tmdb.org/t/p/w500/lyDRtY01krTcs1JP74XL2XxqUb4.jpg', 'https://image.tmdb.org/t/p/w1280/lb1I9lDR3uYwbAZgLxHMiriMKUH.jpg', '本片由中国传统文化的独立的故事组成，在观众面前铺陈开一个极具中式想象力和审美魅力的“妖怪”故事集。其中故事纵览古今、展望未来，从古代故事到科幻想象、 从乡土眷恋到唯美爱情、从生命母题到人性思考，展现着中式想象力、承载着中国民族文化与哲学。影片涵盖多种美术风格以及制作手法：既有传统的二维、剪纸、偶定格动画，又有CG、三渲二的现代技术，还有将素描与中国水墨韵味相结合的创新尝试，是创作者们对中国美学一次多视角的诠释。', '{\"year\": 2023, \"genre\": \"动画, Sci-Fi & Fantasy\", \"studio\": \"陈廖宇\", \"videos\": {\"bilibili\": \"\"}, \"network\": \"bilibili\", \"seasons\": 2, \"trailer\": \"\", \"episodes\": 17}', NULL, NULL, 'https://www.themoviedb.org/tv/139162', '139162', 'tmdb', 1, '2026-05-28 13:15:31', '2026-05-28 13:16:28', 0);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (338, 'anime', '中国奇谭2', 'tmdb-tv-316943', 'https://image.tmdb.org/t/p/w500/gmbaAYlS4PENoSmpZgYsxJOX6pa.jpg', 'https://image.tmdb.org/t/p/w1280/rSnAR12kX29XKwoKfaqvoR53Ar7.jpg', '动画短片集《中国奇谭2》由9部风格迥异的短片组成：《拜山》《大贵人》《大鸟》《耳中人》《今日动物园》《如何成为三条龙》《三郎》《刑天》《小雪》。12位导演在延续中式想象力的基础上，探索多元题材与风格，挖掘中式内核表达，同时增强了现实关照和寓言属性，在奇幻语境中探寻现实命题，对人的自我身份、家庭关系、社会关系等进行思考和探讨。', '{\"year\": 0, \"genre\": \"动画\", \"studio\": \"\", \"videos\": {\"bilibili\": \"\"}, \"network\": \"\", \"seasons\": 1, \"trailer\": \"\", \"episodes\": 9}', NULL, NULL, 'https://www.themoviedb.org/tv/316943', '316943', 'tmdb', 1, '2026-05-28 13:15:31', '2026-05-28 13:15:31', NULL);
