INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (431, 'offline', '弥生·日式沉浸密室', 'misen-escape', 'https://picsum.photos/seed/misen/600/400', NULL, 'X先生金牌密室。日式惊悚氛围拉满，实景搭建超过 200㎡，剧情反转令人头皮发麻。', '{\"date\": \"常驻（需预约）\", \"time\": \"10:00-22:00\", \"price\": \"¥198/人\", \"venue\": \"北京·朝阳大悦城\", \"videos\": {\"youtube\": \"\", \"bilibili\": \"\"}, \"capacity\": \"4-6人/场\", \"difficulty\": \"★★★★☆\", \"event_type\": \"密室逃脱\", \"highlights\": \"日式惊悚,实景,剧情反转,多结局\"}', NULL, NULL, NULL, NULL, 'manual', 1, '2026-05-28 22:30:13', '2026-06-03 16:37:28', 1);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (432, 'offline', '凡几 Common Rare 市集', 'common-rare-market', 'https://picsum.photos/seed/market/600/400', NULL, '国内最好的设计市集之一。70+ 独立品牌、插画、手作、咖啡美食，每次主题都不同。', '{\"date\": \"不定期举办（关注官方）\", \"time\": \"11:00-19:00\", \"price\": \"¥49/人（早鸟）\", \"venue\": \"上海·现所/其他场地\", \"videos\": {\"youtube\": \"\", \"bilibili\": \"\"}, \"event_type\": \"市集\", \"highlights\": \"设计,手作,插画,美食,独立品牌\"}', NULL, NULL, NULL, NULL, 'manual', 1, '2026-05-28 22:30:13', '2026-05-28 22:30:13', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (433, 'offline', '万能青年旅店 全国巡演', 'omnipotent-youth-live', 'https://picsum.photos/seed/wanqing/600/400', NULL, '万青十年磨一剑，《冀西南林路行》巡演。万人合唱《杀死那个石家庄人》的夜晚。', '{\"date\": \"2024-2025 巡演季\", \"time\": \"19:30 开场\", \"price\": \"¥380/580/880\", \"venue\": \"多城市巡演\", \"videos\": {\"youtube\": \"\", \"bilibili\": \"\"}, \"event_type\": \"Live\", \"highlights\": \"摇滚,独立,全场大合唱,必看现场\"}', NULL, NULL, NULL, NULL, 'manual', 1, '2026-05-28 22:30:13', '2026-05-28 22:30:13', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (434, 'offline', '陶艺拉坯体验课', 'pottery-workshop', 'https://picsum.photos/seed/pottery/600/400', NULL, '零基础友好。2 小时从揉泥到拉坯成型，每人带走 2 件作品，老师全程指导。', '{\"date\": \"每周六/日（需预约）\", \"time\": \"14:00-16:00\", \"price\": \"¥268/人\", \"venue\": \"上海·永康路\", \"videos\": {\"youtube\": \"\", \"bilibili\": \"\"}, \"capacity\": \"6人/班\", \"event_type\": \"工作坊\", \"highlights\": \"手作,零基础,2小时,带走成品,解压\"}', NULL, NULL, NULL, NULL, 'manual', 1, '2026-05-28 22:30:13', '2026-05-28 22:30:13', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (435, 'offline', '武康路历史建筑 Citywalk', 'wukang-road-citywalk', 'https://picsum.photos/seed/citywalk/600/400', NULL, '2 小时步行探索上海最优雅的街道。武康大楼、巴金故居、罗密欧阳台、密丹公寓。', '{\"date\": \"每周六/日\", \"time\": \"09:30-11:30\", \"price\": \"¥128/人\", \"venue\": \"上海·武康路（集合：武康大楼）\", \"videos\": {\"youtube\": \"\", \"bilibili\": \"\"}, \"capacity\": \"15人/团\", \"event_type\": \"城市探索\", \"highlights\": \"历史建筑,步行2h,专业讲解,适合拍照\"}', NULL, NULL, NULL, NULL, 'manual', 1, '2026-05-28 22:30:13', '2026-05-28 22:30:13', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (436, 'offline', '安藤忠雄 回顾展', 'ando-exhibition', 'https://picsum.photos/seed/ando/600/400', NULL, '普利兹克奖得主安藤忠雄大型回顾展。光之教堂 1:1 再现，200+ 手稿与模型。', '{\"date\": \"2024.10.01 - 2025.01.19\", \"time\": \"10:00-18:30（周一闭馆）\", \"price\": \"¥150/人\", \"venue\": \"北京·UCCA 尤伦斯当代艺术中心\", \"videos\": {\"youtube\": \"\", \"bilibili\": \"\"}, \"event_type\": \"展览\", \"highlights\": \"建筑模型,手稿,光之教堂,清水混凝土,大师\"}', NULL, NULL, NULL, NULL, 'manual', 1, '2026-05-28 22:30:13', '2026-05-28 22:30:13', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (452, 'game', 'Grand Theft Auto V', 'igdb-239064', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9751.jpg', NULL, 'This bundle contains the original version of Grand Theft Auto V, the standalone game Grand Theft Auto Online and the story mode add-on of Grand Theft Auto V.', '{\"year\": 2015, \"genre\": \"Shooter, Racing, Arcade\", \"theme\": \"Action, Comedy, Sandbox, Open world\", \"rating\": 87.5, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/hvoD7ehZPcM\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/hvoD7ehZPcM\", \"platform\": \"Xbox Series X|S, PlayStation 4, PC (Microsoft Windows), PlayStation 5, Xbox One\", \"websites\": \"https://store.steampowered.com/app/3240220/Grand_Theft_Auto_V_Enhanced/|https://store.epicgames.com/en-US/p/grand-theft-auto-v|https://www.xbox.com/en-gb/games/store/grand-theft-auto-v-xbox-one-xbox-series-x-s/9p8rqh67ttt1|https://store.playstation.com/en-gb/product/EP1004-PPSA01721_00-GTAVCROSSGENBUND|https://www.rockstargames.com/gta-v|https://www.twitch.tv/directory/category/grand-theft-auto-v|https://en.wikipedia.org/wiki/Grand_Theft_Auto_V|https://x.com/RockstarGames|https://www.facebook.com/grandtheftautoV|https://www.instagram.com/rockstargames|https://www.youtube.com/@RockstarGames|https://www.reddit.com/r/GTAV/|https://gta.wiki/w/Grand_Theft_Auto_V\", \"developer\": \"Rockstar North\", \"game_mode\": \"Single player, Multiplayer, Co-operative\", \"publisher\": \"Rockstar Games\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/scocxg.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scocxe.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scocxf.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scocxh.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scocxi.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scocxj.jpg\", \"rating_count\": 333, \"similar_games\": \"Dude Simulator 2, Rising World, Borderlands 3, Citadel: Forged With Fire, Days Gone, Miscreated, Empyrion: Galactic Survival, Dude Simulator, American Fugitive, Force of Nature\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/3240220/Grand_Theft_Auto_V_Enhanced/', '239064', 'igdb', 0, '2026-06-23 18:55:35', '2026-06-23 18:55:35', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (453, 'game', 'Grand Theft Auto: Double Pack', 'igdb-119155', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tvf.jpg', NULL, 'The Grand Theft Auto Double-Pack combines the award-winning Grand Theft Auto 3 and Grand Theft Auto: Vice City together in one collectible release. From the dark and seedy streets of Liberty City\'s underworld to the glamorous hedonism of Vice City in the 1980\'s. Two towns, each brimming with limitless delights and degradation, where anything can happen. Two criminal sagas of greed and desperation that will take you into the world of Grand Theft Auto.', '{\"year\": 2003, \"genre\": \"Shooter, Racing, Simulator, Adventure\", \"theme\": \"Action, Open world\", \"rating\": 0, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/FLyz3kq6p70\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/FLyz3kq6p70\", \"platform\": \"Xbox, PlayStation 2\", \"websites\": \"https://www.rockstargames.com/|https://www.reddit.com/r/GTA|https://www.twitch.tv/directory/game/Grand%20Theft%20Auto%20III|https://gta.fandom.com/wiki/Grand_Theft_Auto_Double_Pack|https://en.wikipedia.org/wiki/Grand_Theft_Auto\", \"developer\": \"Rockstar North\", \"game_mode\": \"Single player\", \"publisher\": \"Rockstar Games\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccq68.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccq69.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccq6c.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccq6a.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccq6b.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccq6d.jpg\", \"rating_count\": 0, \"similar_games\": \"Dude Simulator 2, Borderlands 3, Force of Nature, American Fugitive, Dude Simulator, Miscreated, Immortal: Unchained, The Elder Scrolls VI, Generation Zero, The Sinking City\", \"demo_available\": false}', NULL, NULL, 'https://www.igdb.com/games/119155', '119155', 'igdb', 0, '2026-06-23 18:55:36', '2026-06-23 18:55:36', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (454, 'game', 'Grand Theft Auto V', 'igdb-1020', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lbd.jpg', NULL, 'Grand Theft Auto V is a vast open world game set in Los Santos, a sprawling sun-soaked metropolis struggling to stay afloat in an era of economic uncertainty and cheap reality TV. The game blends storytelling and gameplay in new ways as players repeatedly jump in and out of the lives of the game’s three lead characters, playing all sides of the game’s interwoven story.', '{\"genre\": \"Shooter, Racing, Adventure\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/PIF_fqFZEuk\", \"bilibili\": \"\"}, \"demo_url\": \"\", \"platform\": \"PlayStation 3, PlayStation 4, PC (Microsoft Windows), Xbox 360, Xbox One\", \"developer\": \"Rockstar North\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/271590', '1020', 'igdb', 1, '2026-06-23 18:55:36', '2026-06-23 18:56:21', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (455, 'game', 'Grand Theft Auto VI', 'igdb-52189', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cocaa5.jpg', NULL, 'Grand Theft Auto VI heads to the state of Leonida, home to the neon-soaked streets of Vice City and beyond in the biggest, most immersive evolution of the Grand Theft Auto series yet.', '{\"year\": 2026, \"genre\": \"Shooter, Racing, Adventure\", \"theme\": \"Action, Comedy, Sandbox, Open world\", \"rating\": 0, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/QdBZY2fkU-0\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/QdBZY2fkU-0\", \"platform\": \"Xbox Series X|S, PlayStation 5\", \"websites\": \"https://en.wikipedia.org/wiki/Grand_Theft_Auto_VI|https://www.xbox.com/en-US/games/store/-/9NL3WWNZLZZN|https://www.reddit.com/r/GTA6/|https://x.com/RockstarGames|https://discord.gg/rockstargames|https://store.playstation.com/en-us/concept/10000730|https://www.rockstargames.com/VI|https://youtube.com/@rockstargames|https://www.instagram.com/rockstargames|https://bsky.app/profile/rockstargames.com|https://www.facebook.com/rockstargames|https://gta.wiki/w/Grand_Theft_Auto_VI\", \"developer\": \"Rockstar Games\", \"game_mode\": \"Single player, Multiplayer, Co-operative\", \"publisher\": \"Take-Two Interactive\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/scwpqj.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scpsp7.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scpsp6.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scpsp8.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scpsp9.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlj.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlk.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vll.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlm.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vln.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlo.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlp.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlq.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlr.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vls.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlt.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlu.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc10vlv.jpg\", \"rating_count\": 0, \"similar_games\": \"Borderlands 3, Dude Simulator 2, Days Gone, Cyberpunk 2077, Force of Nature, American Fugitive, Citadel: Forged With Fire, Miscreated, Savage Lands, Dude Simulator\", \"demo_available\": false}', NULL, NULL, 'https://www.igdb.com/games/52189', '52189', 'igdb', 0, '2026-06-23 18:55:36', '2026-06-23 18:55:36', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (456, 'game', 'Grand Theft Auto: Rio de Janeiro', 'igdb-163113', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hhd.jpg', NULL, 'GTA: Rio de Janeiro is a mod of Grand Theft Auto: San Andreas. There are many different versions of the mod, by different people, but all of them try to change the aesthetics of the game (cars, ads, music and others) to new ones based on Rio de Janeiro, a Brazilian city known for being a tourism destination (and also for elevated crime rates). Some version of the mod also change the layout of the city for a new one resembling the Brazilian city.\nThis mod and it\'s variants were very popular in Brazil, where it was sold in parallel shops as a pirate game.', '{\"year\": 2018, \"genre\": \"Shooter\", \"theme\": \"Action, Non-fiction, Sandbox, Open world\", \"rating\": 0, \"videos\": {\"youtube\": \"\", \"bilibili\": \"\"}, \"trailer\": \"\", \"platform\": \"PC (Microsoft Windows), PlayStation 2\", \"websites\": \"\", \"developer\": \"\", \"game_mode\": \"Single player\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/scftzk.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scftzj.jpg\", \"rating_count\": 0, \"similar_games\": \"Dude Simulator, Borderlands 3, Force of Nature, Citadel: Forged With Fire, Just Cause 4, Days Gone, Savage Lands, Miscreated, Dude Simulator 2, Rising World\", \"demo_available\": false}', NULL, NULL, 'https://www.igdb.com/games/163113', '163113', 'igdb', 0, '2026-06-23 18:55:36', '2026-06-23 18:55:36', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (457, 'game', 'Grand Theft Auto: Brasil', 'igdb-163114', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3j7h.jpg', NULL, 'Grand Theft Auto: Brasil is a mod of Grand Theft Auto: San Andreas which changes everything in the game to match with the Brazilian theme. The city is changed to the city of Santos (which is located in the State of São Paulo).', '{\"year\": 2019, \"genre\": \"Shooter\", \"theme\": \"Action, Open world\", \"rating\": 0, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/MuZIx9pdRqM\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/MuZIx9pdRqM\", \"platform\": \"PC (Microsoft Windows)\", \"websites\": \"https://discord.gg/24NJsrc|https://tcgtabrasil.wixsite.com/tcgtabrasil|https://www.youtube.com/channel/UCDo6pvz5Kwsw3IG2WAE7wyA|https://www.facebook.com/tcgtabr\", \"developer\": \"MixMods\", \"game_mode\": \"Single player, Multiplayer\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccfb3.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccfb2.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccfb4.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sccfb1.jpg\", \"rating_count\": 0, \"similar_games\": \"Borderlands 3, Dude Simulator, Call of Duty: Modern Warfare, Call of Duty: Mobile, Phantomers Insurreccion, Free Fire, The Elder Scrolls VI, Black Squad, GentleMoon 2, Rico\", \"demo_available\": false}', NULL, NULL, 'https://www.igdb.com/games/163114', '163114', 'igdb', 0, '2026-06-23 18:55:36', '2026-06-23 18:55:36', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (458, 'game', 'Grand Theft Auto: Director\'s Cut', 'igdb-327467', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co98u8.jpg', NULL, 'Grand Theft Auto: Director\'s Cut is a video game compilation, developed by DMA Design and published by Rockstar Games. It was first released in May 1999. The compilation contains two discs - Grand Theft Auto and Grand Theft Auto: London 1969.', '{\"year\": 1999, \"genre\": \"Shooter, Racing, Adventure\", \"theme\": \"Action, Sandbox, Open world\", \"rating\": 0, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/Z7JyLZgHfUA\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/Z7JyLZgHfUA\", \"platform\": \"PC (Microsoft Windows), DOS, PlayStation\", \"websites\": \"\", \"developer\": \"DMA Design\", \"game_mode\": \"Single player\", \"publisher\": \"Rockstar Games\", \"screenshots\": \"\", \"rating_count\": 0, \"similar_games\": \"Borderlands 3, Days Gone, Dude Simulator 2, Force of Nature, Citadel: Forged With Fire, Grand Theft Auto VI, American Fugitive, Savage Lands, Dude Simulator, Miscreated\", \"demo_available\": false}', NULL, NULL, 'https://www.igdb.com/games/327467', '327467', 'igdb', 0, '2026-06-23 18:55:36', '2026-06-23 18:55:36', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (459, 'game', 'Grand Theft Auto III', 'igdb-730', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lb8.jpg', NULL, 'Featuring a fully 3-D living city, a combination of narrative driven and non-linear gameplay and a completely open environment, Grand Theft Auto III represents a huge leap forward in interactive entertainment. For the first time, players are put at the heart of their very own gangster movie, and let loose in a fully-realised 3 dimensional city, in which anything can happen and probably will.\n\nWith a cast of hundreds, 50 plus vehicles, ranging from sports cars to ice cream trucks and from boats to buses, 3 hours of music, including opera, reggae, house, drum and bass, pop and disco, a huge array of street ready weapons and some of the seediest characters in video game history, Grand Theft Auto 3 is a sprawling epic which will show you that sometimes, crime can pay and sometimes it can pay you back. Available now for PlayStation2, Xbox, PC and Macintosh.', '{\"year\": 2001, \"genre\": \"Shooter, Racing, Simulator, Adventure\", \"theme\": \"Action, Sandbox, Open world\", \"rating\": 84.6, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/PtbUORusNvo\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/PtbUORusNvo\", \"platform\": \"Xbox, PlayStation 4, Android, PC (Microsoft Windows), iOS, Mac, PlayStation 2\", \"websites\": \"https://store.steampowered.com/app/12100|https://apps.apple.com/us/app/grand-theft-auto-iii/id479662730|https://play.google.com/store/apps/details?id=com.rockstar.gta3|https://apps.apple.com/us/app/grand-theft-auto-iii/id479662730|http://www.rockstargames.com/grandtheftauto3|https://www.twitch.tv/directory/game/Grand%20Theft%20Auto%20III|https://en.wikipedia.org/wiki/Grand_Theft_Auto_III|https://gta.wiki/w/Grand_Theft_Auto_III\", \"developer\": \"DMA Design\", \"game_mode\": \"Single player\", \"publisher\": \"Take-Two Interactive\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5kn.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5kp.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5kq.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5ky.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5l1.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5l2.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5l3.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5l4.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5l5.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sch5kw.jpg\", \"rating_count\": 1591, \"similar_games\": \"Grand Theft Auto IV, Grand Theft Auto, Grand Theft Auto: Vice City, Grand Theft Auto V, Grand Theft Auto 2, Watch Dogs 2, Sleeping Dogs, Grand Theft Auto: San Andreas, Grand Theft Auto: Vice City Stories, Dude Simulator 2\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/12100', '730', 'igdb', 0, '2026-06-23 18:55:36', '2026-06-23 18:55:36', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (460, 'game', 'Grand Theft Auto', 'igdb-980', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lb0.jpg', NULL, 'Grand Theft Auto is the first game in the Grand Theft Auto series and a sandbox-crime game published by Rockstar Games.\n\nThe original Grand Theft Auto is made up of a series of levels each set in one of the three cities in the game. In each level, the player has a target number of points to achieve, and five lives to attain the score.\n\nThe score counter doubles as a money meter; the player can spend this money on paint jobs and various other things. However, any money spent is of course taken away from the score, making the goal that little bit further away.\n\nOn obtaining the target number of points, the player must then drive to a certain location to complete the level, which allows progress to the next one.', '{\"year\": 1997, \"genre\": \"Shooter, Racing, Adventure\", \"theme\": \"Action, Sandbox, Open world\", \"rating\": 75.1, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/02kMHWKaMg8\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/02kMHWKaMg8\", \"platform\": \"Nintendo 64, PC (Microsoft Windows), DOS, PlayStation\", \"websites\": \"https://store.steampowered.com/app/12170|http://www.rockstargames.com/classics/gta.html|https://en.wikipedia.org/wiki/Grand_Theft_Auto_(video_game)|https://www.reddit.com/r/GTA|https://www.twitch.tv/directory/game/Grand%20Theft%20Auto|https://gta.wiki/w/Grand_Theft_Auto_(1997_game)\", \"developer\": \"DMA Design\", \"game_mode\": \"Single player, Multiplayer\", \"publisher\": \"BMG Interactive\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/vyg5gb8whxurxjyfqfnf.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/svjb1qvyctatpiqgawkj.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/pbofcxzxuwjk8uqfejvb.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/yk6qjnjxpdr5sxc2jnfj.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/issnz2fcwsf6mr2x0pgu.jpg\", \"rating_count\": 492, \"similar_games\": \"Grand Theft Auto 2, Grand Theft Auto: Vice City, Grand Theft Auto III, Watch Dogs 2, Grand Theft Auto: Vice City Stories, Grand Theft Auto IV, Grand Theft Auto V, Watch Dogs, Grand Theft Auto: San Andreas, Grand Theft Auto: Chinatown Wars\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/12170', '980', 'igdb', 0, '2026-06-23 18:55:36', '2026-06-23 18:55:36', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (461, 'game', 'Grand Theft Auto: Misterix', 'igdb-253324', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ylz.jpg', NULL, 'A San Andreas hack that adds old school myths and classic horror monsters into the game for you to hunt!', '{\"year\": 2020, \"genre\": \"Shooter\", \"theme\": \"Horror\", \"rating\": 0, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/tMa0ZGDKMNQ\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/tMa0ZGDKMNQ\", \"platform\": \"PlayStation 2\", \"websites\": \"\", \"developer\": \"nadalao\", \"game_mode\": \"Single player\", \"publisher\": \"\", \"screenshots\": \"\", \"rating_count\": 0, \"similar_games\": \"F.E.A.R. 2: Project Origin, Bubble Fighter, Apsulov: End of Gods, Infliction, Five Nights at Freddy\'s, The Postman Shoots Twice, When Pigs Can Fly: Enter The Aporkalypse, Apollo 13: The Lost Tapes VR, City of the Evil Dead, 5 Nights At Grek\'s Hotel\", \"demo_available\": false}', NULL, NULL, 'https://www.igdb.com/games/253324', '253324', 'igdb', 0, '2026-06-23 18:55:36', '2026-06-23 18:55:36', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (462, 'game', 'Tukoni: Forest Keepers', 'igdb-141273', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa6c9.jpg', NULL, 'Tukoni: Forest Keepers is a cute and cozy puzzle adventure, based on a series of award-winning books by the Ukrainian artist Oksana Bula. Play as the forest spirit Tukoni as you meet unique characters, solve captivating puzzles, brew fragrant tea and explore a magical world filled with kindness.', '{\"year\": 2026, \"genre\": \"Point-and-click, Platform, Puzzle, Adventure, Indie\", \"theme\": \"Fantasy, Kids\", \"rating\": 75.9, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/9EoytHy0uyg\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/9EoytHy0uyg\", \"platform\": \"PC (Microsoft Windows)\", \"websites\": \"https://www.facebook.com/TukoniTribe|https://x.com/dreamoperator|https://www.instagram.com/tukoni_tribe/|https://store.steampowered.com/app/2933200/Tukoni_Forest_Keepers/|https://bsky.app/profile/dream-operator.bsky.social|https://tukoni.itch.io/tukoni|https://store.epicgames.com/en-US/p/tukoni-forest-keepers-7ef952|https://discord.gg/Vrh2wBvGhx|https://www.youtube.com/@Dream.Operator|https://www.twitch.tv/directory/game/Tukoni|https://tukoni.world/|https://uk.wikipedia.org/wiki/Tukoni|https://www.gog.com/en/game/tukoni_forest_keepers\", \"developer\": \"\", \"game_mode\": \"Single player\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/scy5ie.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scy5ij.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scy5if.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scy5ig.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scy5ih.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scy5ii.jpg\", \"rating_count\": 10, \"similar_games\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/2933200/Tukoni_Forest_Keepers/', '141273', 'igdb', 0, '2026-06-23 19:00:23', '2026-06-23 19:00:23', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (463, 'game', 'Backrooms: Escape Together', 'igdb-220348', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8o6i.jpg', NULL, 'A visually lifelike 1-6 player co-op survival horror made in Unreal Engine 5. Explore procedurally generated levels that host liminal environments, puzzles, and entities with new levels and content added regularly. You are at the mercy of what\'s lurking and must do whatever it takes to escape.', '{\"year\": 2026, \"genre\": \"Adventure, Indie\", \"theme\": \"Horror, Survival\", \"rating\": 79.8, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/jmv21__96HA\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/jmv21__96HA\", \"platform\": \"PC (Microsoft Windows), PlayStation 5\", \"websites\": \"https://store.steampowered.com/app/2141730|https://www.youtube.com/@BackroomsEscapeTogether|https://discord.gg/Cb4pQdCDX6|https://store.playstation.com/en-us/product/UB1588-PPSA29906_00-0549164535498989|https://www.backroomsescapetogether.com/|https://www.twitch.tv/directory/game/Backrooms:%20Escape%20Together\", \"developer\": \"\", \"game_mode\": \"Single player, Multiplayer, Co-operative\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/scj7oy.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sctnzt.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sctnzx.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sctnzy.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sctnzz.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scto00.jpg\", \"rating_count\": 18, \"similar_games\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/2141730', '220348', 'igdb', 0, '2026-06-23 19:00:23', '2026-06-23 19:00:23', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (464, 'game', 'Gothic 1 Remake', 'igdb-148227', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9lfu.jpg', NULL, 'Gothic 1 Remake is an action role-playing game set in a third-person perspective within a fantasy open world. It is a remake of the 2001 game Gothic, developed by Alkimia Interactive using Unreal Engine 5. The player controls a nameless prisoner sent into the Valley of Mines, a penal colony surrounded by a magical barrier. The game features NPC routines, faction-based quest paths, and a progression system where the player starts with no skills and must learn them from trainers. Navigation is done without a minimap, and the game world is 10 to 30 percent larger than the original, with expanded chapters and additional quest content. Combat and skill systems are based on the original game\'s design.', '{\"year\": 2026, \"genre\": \"Role-playing (RPG), Adventure\", \"theme\": \"Action, Fantasy, Open world\", \"rating\": 88.5, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/u2lQjmmW1B0\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/u2lQjmmW1B0\", \"platform\": \"Xbox Series X|S, PC (Microsoft Windows), PlayStation 5\", \"websites\": \"https://store.steampowered.com/app/1297900/Gothic_1_Remake|https://www.twitch.tv/directory/category/gothic-1-remake|https://www.gog.com/game/gothic_1_remake|https://www.instagram.com/thegothicgame|https://discord.gg/invite/gothic|https://twitter.com/gothicthegame|http://www.gothic-game.com|https://www.youtube.com/@thegothicgame|https://store.playstation.com/en-us/concept/10005976|https://en.wikipedia.org/wiki/Gothic_1_Remake|https://www.xbox.com/en-us/games/store/gothic-1-remake/9nbrlcpw4zgv|https://gothic.wiki/w/Gothic_1_Remake\", \"developer\": \"\", \"game_mode\": \"Single player\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc9o8z.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc9o90.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc9o91.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc9o92.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc9o93.jpg\", \"rating_count\": 20, \"similar_games\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/1297900/Gothic_1_Remake', '148227', 'igdb', 0, '2026-06-23 19:00:23', '2026-06-23 19:00:23', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (465, 'game', 'Mina the Hollower', 'igdb-189781', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4g15.jpg', NULL, 'Mina the Hollower is a bone-chilling action-adventure game featuring classic gameplay and an 8-bit aesthetic in the style of Game Boy Color, refined for the modern era.\n\nQuick and deliberate 60fps action combat, captivating world design, and top-down adventuring combine in a nostalgic blend. Whip foes, burrow through the ground, and explore a pixel-perfect world in Mina the Hollower, a brand new game from the developers who brought you Shovel Knight!', '{\"year\": 2026, \"genre\": \"Platform, Role-playing (RPG), Adventure, Indie\", \"theme\": \"Action, Fantasy, Horror\", \"rating\": 82.7, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/_Fx0aJCRRpE\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/_Fx0aJCRRpE\", \"platform\": \"Xbox Series X|S, Linux, Nintendo Switch 2, PC (Microsoft Windows), PlayStation 5, Mac, Nintendo Switch\", \"websites\": \"https://discord.gg/ebfPBH7J7Z|https://www.nintendo.com/us/store/products/mina-the-hollower-switch-2/|https://en.wikipedia.org/wiki/Mina_the_Hollower|https://www.instagram.com/yachtclubgames/|https://store.playstation.com/en-us/concept/10010918|https://bsky.app/profile/did:plc:n7bzcix7uj2kssdw2kt255ez|https://www.youtube.com/yachtclubgames/|https://www.facebook.com/YachtClubGames|https://twitter.com/YachtClubGames|https://store.steampowered.com/app/1875580/Mina_the_Hollower|https://www.yachtclubgames.com/games/mina-the-hollower|https://www.twitch.tv/directory/game/Mina%20the%20Hollower|https://www.gog.com/en/game/mina_the_hollower|https://www.xbox.com/en-us/games/store/mina-the-hollower/9nztglvs99x3|https://minathehollower.wiki.gg/|https://www.reddit.com/r/MinaTheHollower/\", \"developer\": \"\", \"game_mode\": \"Single player\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/scfkjl.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scfkjm.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scgr2b.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scgr2c.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scgr2d.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scgr2e.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scgr2f.jpg\", \"rating_count\": 21, \"similar_games\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/1875580/Mina_the_Hollower', '189781', 'igdb', 0, '2026-06-23 19:00:23', '2026-06-23 19:00:23', NULL);
