tps://images.igdb.com/igdb/image/upload/t_screenshot_big/scvsrw.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scvsrx.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scvsry.jpg\", \"rating_count\": 10, \"similar_games\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/2827230', '288461', 'igdb', 0, '2026-06-23 19:00:23', '2026-06-23 19:00:23', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (467, 'game', '007 First Light', 'igdb-141114', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaoiz.jpg', NULL, '007 First Light is a thrilling espionage action-adventure game from IO Interactive. Players follow James Bond as a young, resourceful, and sometimes reckless recruit in MI6\'s training program and discover an origin story of the world\'s most famous spy.', '{\"year\": 2026, \"genre\": \"Shooter, Adventure\", \"theme\": \"Action, Stealth\", \"rating\": 82.0, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/slAhuh21ii8\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/slAhuh21ii8\", \"platform\": \"Xbox Series X|S, Nintendo Switch 2, PC (Microsoft Windows), PlayStation 5\", \"websites\": \"https://jamesbond.fandom.com/wiki/007_First_Light|https://discord.gg/007gameioi|https://www.youtube.com/@007GameIOI|https://www.instagram.com/007GameIOI|https://en.wikipedia.org/wiki/007_First_Light|https://www.facebook.com/007Gameioi|https://bsky.app/profile/007game.ioi.dk|https://store.epicgames.com/p/007-first-light-182cea|https://ioi.dk/007firstlightgame|https://store.steampowered.com/app/3768760/007_First_Light/|https://www.xbox.com/en-us/games/store/007-first-light/9pn198b459vb|https://store.playstation.com/en-us/concept/10006560/|https://www.reddit.com/r/007FirstLight/|https://x.com/IOInteractive|https://www.twitch.tv/directory/category/007-first-light\", \"developer\": \"\", \"game_mode\": \"Single player\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/scx79u.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scx79v.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scx79w.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scx79x.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scyx6q.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scyx6r.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scz0hs.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scz0ht.jpg\", \"rating_count\": 87, \"similar_games\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/3768760/007_First_Light/', '141114', 'igdb', 0, '2026-06-23 19:00:23', '2026-06-23 19:00:23', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (468, 'game', 'LEGO Batman: Legacy of the Dark Knight', 'igdb-361855', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coab09.jpg', NULL, 'Rise as the Dark Knight and experience the essential Batman story in a bold, action-packed adventure with hard-hitting combat, an open-world Gotham City, and the signature LEGO charm that fans know and love.', '{\"year\": 2026, \"genre\": \"Puzzle, Adventure\", \"theme\": \"Action, Comedy\", \"rating\": 84.6, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/1hQAoGj01Rc\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/1hQAoGj01Rc\", \"platform\": \"Xbox Series X|S, Nintendo Switch 2, PC (Microsoft Windows), PlayStation 5\", \"websites\": \"https://store.playstation.com/en-us/concept/10008537|https://en.wikipedia.org/wiki/Lego_Batman:_Legacy_of_the_Dark_Knight|https://www.youtube.com/@WBGAMES|https://x.com/LEGODCGame|https://www.instagram.com/legodcgame/|https://www.facebook.com/LEGOBatmanGame/|https://store.steampowered.com/app/2215200|https://legobatmangame.com/|https://epicgames.com/p/lego-batman-legacy-of-the-dark-knight-c82b6b|https://www.nintendo.com/us/store/products/lego-batman-legacy-of-the-dark-knight-switch-2/|https://www.xbox.com/en-US/games/store/lego-batman-legacy-of-the-dark-knight/9PFKP8Z66G1J/0010|https://www.twitch.tv/directory/category/lego-batman-legacy-of-the-dark-knight|https://brickipedia.fandom.com/wiki/LEGO_Batman:_Legacy_of_the_Dark_Knight\", \"developer\": \"\", \"game_mode\": \"Single player, Multiplayer, Co-operative, Split screen\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/scymdu.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scymdv.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scymdw.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scymdx.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scymdy.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scymdz.jpg\", \"rating_count\": 28, \"similar_games\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/2215200', '361855', 'igdb', 0, '2026-06-23 19:00:23', '2026-06-23 19:00:23', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (469, 'game', 'Forza Horizon 6', 'igdb-348330', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobc5n.jpg', NULL, 'Discover the breathtaking landscapes of Japan in over 550 real-world cars and become a racing Legend at the Horizon Festival. Start your journey as a tourist and explore a world full of hit music and Japanese culture. Build a Valley Estate, acquire awe-inspiring homes, and display your prized car collection in fully Customizable Garages. Cruise the roads with your friends and join Car Meets around Japan, unleash your imagination with EventLab and build together in Horizon CoLab.', '{\"year\": 2026, \"genre\": \"Racing, Simulator, Sport, Arcade\", \"theme\": \"Action, Open world\", \"rating\": 80.5, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/VXedKqX5Wa4\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/VXedKqX5Wa4\", \"platform\": \"Xbox Series X|S, PC (Microsoft Windows), PlayStation 5\", \"websites\": \"https://store.steampowered.com/app/2483190|https://www.xbox.com/en-us/games/store/forza-horizon-6/9nr1r1xwlcnb|https://www.twitch.tv/directory/category/forza-horizon-6|https://forza.net/|https://forza.fandom.com/wiki/Forza_Horizon_6|https://x.com/forzahorizon|https://www.facebook.com/forzamotorsport|https://www.instagram.com/forzahorizonofficial|https://www.youtube.com/@Forza|https://en.wikipedia.org/wiki/Forza_Horizon_6|https://www.reddit.com/r/ForzaHorizon|https://discord.gg/forza|https://bsky.app/profile/horizon.forza.net|https://store.playstation.com/en-us/concept/10016335\", \"developer\": \"\", \"game_mode\": \"Single player, Multiplayer, Co-operative\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc11fdi.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc11fdj.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc11fdk.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc11fdl.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc11fdp.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc11fdn.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc11fdm.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc11fdq.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc11fdo.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc13cgq.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc13cgr.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc13cgs.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/sc13cgt.jpg\", \"rating_count\": 58, \"similar_games\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/2483190', '348330', 'igdb', 0, '2026-06-23 19:00:23', '2026-06-23 19:00:23', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (470, 'game', 'Subnautica 2', 'igdb-320140', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8yd0.jpg', NULL, 'Subnautica 2 is an underwater survival adventure set on an all-new alien world, developed by Unknown Worlds. Play alone or with friends in 4-player co-op. Adapt to survive by building custom bases and crafting tools. Explore the unknown to uncover the mysteries hidden within the depths.', '{\"year\": 2026, \"genre\": \"Adventure\", \"theme\": \"Action, Science fiction, Survival\", \"rating\": 90.0, \"videos\": {\"youtube\": \"https://www.youtube.com/embed/WS0vTRl_2PQ\", \"bilibili\": \"\"}, \"trailer\": \"https://www.youtube.com/embed/WS0vTRl_2PQ\", \"platform\": \"Xbox Series X|S, PC (Microsoft Windows)\", \"websites\": \"https://discord.gg/subnautica|https://www.reddit.com/r/subnautica/|https://www.youtube.com/subnautica|https://store.epicgames.com/p/subnautica-2-d27f94|https://www.twitch.tv/directory/category/subnautica-2|https://www.xbox.com/en-US/games/store/subnautica-2/9PJPCB188SVG|https://bsky.app/profile/subnautica.bsky.social|https://twitter.com/Subnautica|https://www.subnautica.com/|https://www.instagram.com/subnautica|https://store.steampowered.com/app/1962700/|https://www.facebook.com/subnautica|https://wiki.subnautica.com/sn2/|https://en.wikipedia.org/wiki/Subnautica_2\", \"developer\": \"\", \"game_mode\": \"Single player, Multiplayer, Co-operative\", \"publisher\": \"\", \"screenshots\": \"https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu8a0.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu8a1.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu8a2.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu8a3.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu85q.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu85r.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu85s.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu85t.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu85u.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu8a4.jpg|https://images.igdb.com/igdb/image/upload/t_screenshot_big/scu85v.jpg\", \"rating_count\": 34, \"similar_games\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/1962700/', '320140', 'igdb', 0, '2026-06-23 19:00:23', '2026-06-23 19:00:23', NULL);
INSERT INTO `items` (`id`, `type`, `title`, `slug`, `cover_url`, `wide_cover_url`, `description`, `info_json`, `media_url`, `poster_url`, `external_link`, `external_id`, `source`, `status`, `created_at`, `updated_at`, `carousel_order`) VALUES (471, 'game', 'Mixtape', 'igdb-305157', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coc2wi.jpg', NULL, 'Mixtape is a narrative adventure game developed by Beethoven & Dinosaur and published by Annapurna Interactive. Set during the last night of high school, it follows three friends as they revisit memories connected to music, youth and leaving home. The game combines story scenes with playable vignettes, including skating, parties, and other moments, all framed by a licensed soundtrack.', '{\"genre\": \"Music, Adventure, Indie, Visual Novel\", \"videos\": {\"youtube\": \"https://www.youtube.com/embed/cCTH8R6RD74\", \"bilibili\": \"\"}, \"demo_url\": \"\", \"platform\": \"Xbox Series X|S, Nintendo Switch 2, PC (Microsoft Windows), PlayStation 5\", \"developer\": \"\", \"demo_available\": false}', NULL, NULL, 'https://store.steampowered.com/app/2582320/Mixtape/', '305157', 'igdb', 1, '2026-06-23 19:00:23', '2026-06-23 19:00:45', NULL);
