-- Table structure for items
-- ----------------------------
DROP TABLE IF EXISTS `items`;
CREATE TABLE `items` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `type` varchar(20) NOT NULL COMMENT 'game, movie, anime, boardgame, model, ...',
  `title` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `cover_url` varchar(512) DEFAULT NULL,
  `wide_cover_url` varchar(512) DEFAULT NULL,
  `description` text,
  `info_json` json DEFAULT NULL COMMENT 'elastic attributes',
  `media_url` varchar(512) DEFAULT NULL,
  `poster_url` varchar(512) DEFAULT NULL COMMENT 'vertical poster image',
  `external_link` varchar(512) DEFAULT NULL,
  `external_id` varchar(100) DEFAULT NULL COMMENT 'Steam AppID, TMDB ID',
  `source` varchar(30) DEFAULT 'manual' COMMENT 'manual, steam, tmdb, itch',
  `status` tinyint DEFAULT '1' COMMENT '1-online 0-offline',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `carousel_order` int DEFAULT NULL COMMENT 'NULL=not in carousel, 0,1,2... = display order',
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`),
  KEY `idx_type` (`type`),
  KEY `idx_slug` (`slug`)
) ENGINE=InnoDB AUTO_INCREMENT=472 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

